// Extrae cada ticket del payload y le adjunta el contexto de la aprobación.
// Input esperado del backend:
// { approval_id, requirement_id, requirement_title, project_name,
//   approved_by, manager_email, tickets: [{...}] }
const body = $input.first().json;
const base = {
  approval_id: body.approval_id,
  requirement_id: body.requirement_id,
  requirement_title: body.requirement_title || 'Sin título',
  project_name: body.project_name || 'Sin proyecto',
  approved_by: body.approved_by || 'Manager',
  manager_email: body.manager_email || ''
};

if (!Array.isArray(body.tickets) || body.tickets.length === 0) {
  throw new Error('El payload no contiene tickets.');
}

return body.tickets.map(ticket => ({
  json: { ...base, ...ticket }
}));

// Construye el HTML de la tabla resumen para el email al manager.
const tickets = $input.first().json.tickets;
const first = tickets[0] || {};
const requirementTitle = first.requirement_title || 'Plan aprobado';
const projectName = first.project_name || '';
const approvedBy = first.approved_by || 'Manager';
const managerEmail = first.manager_email || '';

const rows = tickets.map(t => {
  const riskColor = t.risk_pct > 60 ? '#dc2626' : t.risk_pct > 40 ? '#d97706' : '#16a34a';
  return `<tr>
    <td style="padding:8px 12px;border-top:1px solid #e5e5e5">${t.title}</td>
    <td style="padding:8px 12px;border-top:1px solid #e5e5e5">${t.assignee_name || 'Sin asignar'}</td>
    <td style="padding:8px 12px;border-top:1px solid #e5e5e5">${t.priority}</td>
    <td style="padding:8px 12px;border-top:1px solid #e5e5e5">${t.estimate_hours}h</td>
    <td style="padding:8px 12px;border-top:1px solid #e5e5e5;color:${riskColor};font-weight:600">${t.risk_pct}%</td>
    <td style="padding:8px 12px;border-top:1px solid #e5e5e5">${t.deadline || '—'}</td>
  </tr>`;
}).join('');

const highRisk = tickets.filter(t => t.risk_pct > 60).length;
const totalHours = tickets.reduce((a, t) => a + (t.estimate_hours || 0), 0);

return [{
  json: {
    manager_email: managerEmail,
    requirement_title: requirementTitle,
    project_name: projectName,
    approved_by: approvedBy,
    approval_id: first.approval_id,
    total_tickets: tickets.length,
    total_hours: totalHours,
    high_risk_count: highRisk,
    summary_html: `<div style="font-family:sans-serif;max-width:700px;margin:0 auto">
  <h2 style="color:#111">Plan aprobado: ${requirementTitle}</h2>
  <p>Proyecto: <strong>${projectName}</strong> · Aprobado por: <strong>${approvedBy}</strong></p>
  <div style="display:flex;gap:24px;margin:16px 0">
    <div style="background:#f5f5f5;padding:12px 20px;border-radius:8px;text-align:center">
      <div style="font-size:28px;font-weight:700">${tickets.length}</div>
      <div style="color:#6b7280;font-size:13px">tickets</div>
    </div>
    <div style="background:#f5f5f5;padding:12px 20px;border-radius:8px;text-align:center">
      <div style="font-size:28px;font-weight:700">${totalHours}h</div>
      <div style="color:#6b7280;font-size:13px">horas estimadas</div>
    </div>
    ${highRisk > 0 ? `<div style="background:#fef2f2;padding:12px 20px;border-radius:8px;text-align:center">
      <div style="font-size:28px;font-weight:700;color:#dc2626">${highRisk}</div>
      <div style="color:#dc2626;font-size:13px">riesgo alto</div>
    </div>` : ''}
  </div>
  <table style="border-collapse:collapse;width:100%">
    <tr style="background:#111;color:#fff">
      <th style="padding:8px 12px;text-align:left">Ticket</th>
      <th style="padding:8px 12px;text-align:left">Asignado a</th>
      <th style="padding:8px 12px;text-align:left">Prioridad</th>
      <th style="padding:8px 12px;text-align:left">Horas</th>
      <th style="padding:8px 12px;text-align:left">Riesgo</th>
      <th style="padding:8px 12px;text-align:left">Deadline</th>
    </tr>
    ${rows}
  </table>
  <p style="margin-top:24px;color:#6b7280;font-size:13px">Meeting → Tickets PM · Cursor Buildathon El Salvador 2026</p>
</div>`
  }
}];
